"""Gold: AI-generated summaries for entries.

Calls Ollama llama3:70b to generate 1-3 sentence summaries for entries
above the min_summary_chars threshold. Config-driven prompts and model.
"""
import sys
sys.path.insert(0, "/workspace")


def _call_ollama(prompt: str, url: str, model: str) -> str | None:
    """Call Ollama API. Returns response text or None on failure."""
    import requests
    try:
        resp = requests.post(
            f"{url}/api/generate",
            json={"model": model, "prompt": prompt, "stream": False},
            timeout=300,
        )
        if resp.status_code == 200:
            return resp.json().get("response", "").strip()
    except Exception as e:
        print(f"    Ollama error: {e}", flush=True)
    return None


def model(dbt, session):
    dbt.config(materialized="table")

    from dlt.lib.tabletop_cleanup import load_config, _log
    from pathlib import Path
    from datetime import datetime, timezone
    import pandas as pd

    configs_dir = Path("/workspace/documents/tabletop_rules/configs")

    entries_df = dbt.ref("silver_entries").df()
    index_df = dbt.ref("gold_entry_index").df()

    # Merge to get entry_type
    merged = entries_df.merge(
        index_df[["entry_id", "entry_type"]],
        on="entry_id", how="left",
    )

    all_rows = []
    now = datetime.now(timezone.utc)

    for sf in merged["source_file"].unique():
        config = load_config(Path(sf), configs_dir)
        gold_config = config.get("gold", {})
        ollama_url = gold_config.get("ollama_url", "http://host.docker.internal:11434")
        ollama_model = gold_config.get("ollama_model", "llama3:70b")
        min_chars = gold_config.get("min_summary_chars", 200)
        prompt_template = gold_config.get("summary_prompt", "Summarize: {content}")

        sf_entries = merged[merged["source_file"] == sf]
        to_summarize = sf_entries[sf_entries["char_count"] >= min_chars]

        _log(f"  AI Summaries: {len(to_summarize)} entries to summarize for {sf}")

        for i, (_, row) in enumerate(to_summarize.iterrows()):
            entry_type = row.get("entry_type", "entry") or "entry"
            entry_title = row.get("entry_title", "") or ""
            content = row["content"]

            # Truncate very long content to avoid token limits
            if len(content) > 3000:
                content = content[:3000] + "..."

            prompt = prompt_template.format(
                entry_type=entry_type,
                entry_title=entry_title,
                content=content,
            )

            summary = _call_ollama(prompt, ollama_url, ollama_model)

            all_rows.append({
                "entry_id": int(row["entry_id"]),
                "source_file": sf,
                "entry_title": entry_title,
                "entry_type": entry_type,
                "summary": summary or "",
                "summarized_at": now,
            })

            if (i + 1) % 25 == 0:
                _log(f"    {i + 1}/{len(to_summarize)} summarized")

        _log(f"  AI Summaries: done ({len(to_summarize)} entries)")

    return pd.DataFrame(all_rows) if all_rows else pd.DataFrame(
        columns=["entry_id", "source_file", "entry_title", "entry_type",
                 "summary", "summarized_at"]
    )


